public class TicketService
{
    private readonly EventBookingContext _context;

    public TicketService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var @event = await _context.Events.FindAsync(eventId);

        if (@event == null || quantity <= 0)
            return false;

        // Start a transaction
        using (var transaction = await _context.Database.BeginTransactionAsync())
        {
            try
            {
                // Reload the entity to ensure we have the latest state from the database
                await _context.Entry(@event).ReloadAsync();

                if (@event.AvailableSeats < quantity)
                    return false;

                @event.AvailableSeats -= quantity;

                _context.Entry(@event).State = EntityState.Modified;
                await _context.SaveChangesAsync();

                // Commit the transaction
                await transaction.CommitAsync();
                return true;
            }
            catch (Exception)
            {
                // Rollback the transaction in case of an error
                await transaction.RollbackAsync();
                throw;
            }
        }
    }
